SELECT c.id, c.group_id, g.group_name, c.service_id, s.service_name, c.competitor_name, c.stat_month, c.quantity, c.remark, c.status AS status, c.updated_time FROM biz_group_competitor c LEFT JOIN crm_group g ON c.group_id = g.id LEFT JOIN biz_service s ON c.service_id = s.id WHERE c.deleted_flag = 0
AND c.group_id IN #{gid}
AND c.status = #{status}
AND c.status IN #{s}
AND (c.competitor_name LIKE CONCAT('%', #{keyword}, '%') OR s.service_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.updated_time DESC

SELECT COUNT(1) FROM biz_group_competitor c WHERE c.deleted_flag = 0

    AND c.group_id IN
    #{gid}


    AND c.status = #{status}


    AND c.status IN
    #{s}
